import{_ as l,o as e,c as r,ag as o}from"./chunks/framework.f_9xDHrT.js";const u=JSON.parse('{"title":"认证流程","description":"获取 MissFisher 使用权、替换识别凭证，以及使用临时免验凭证。","frontmatter":{"title":"认证流程","description":"获取 MissFisher 使用权、替换识别凭证，以及使用临时免验凭证。"},"headers":[],"relativePath":"manual/auth.md","filePath":"manual/auth.md","lastUpdated":1778082333000}'),s={name:"manual/auth.md"};function a(t,i,d,c,n,h){return e(),r("div",null,[...i[0]||(i[0]=[o('<h1 id="认证" tabindex="-1">认证 <a class="header-anchor" href="#认证" aria-label="Permalink to &quot;认证&quot;">​</a></h1><blockquote><p>认证完全免费。</p></blockquote><h2 id="识别凭证" tabindex="-1">识别凭证 <a class="header-anchor" href="#识别凭证" aria-label="Permalink to &quot;识别凭证&quot;">​</a></h2><p>识别凭证会在登陆后，于 MissFisher 主界面的信息页中自动生成。</p><p><strong>识别凭证有两种：</strong></p><ul><li><strong>M 开头的设备识别凭证（机器码）</strong>：<br> 对应当前的设备信息。<br> 使用机器码认证后，任何角色都可在该设备上使用 MissFisher。</li><li><strong>S 开头的账号识别凭证（账号码）</strong>：<br> 对应当前登陆的账号。<br> 使用账号码认证后，该账号码对应账号下的任何角色都可使用 MissFisher。</li></ul><details><summary>设备识别凭证的变化时机</summary><p><strong>设备识别凭证的变化时机：</strong></p><ul><li>在不同的设备上，会生成不同的设备识别凭证。</li><li>另外，设备信息变化时，也将导致设备识别凭证发生变化。 <ul><li>导致变化的常见情形：<br> 更换了组成电脑的重要配件<br> 使用一些手段变更了配件在软件层面的识别信息</li></ul></li></ul></details><h2 id="认证-1" tabindex="-1">认证 <a class="header-anchor" href="#认证-1" aria-label="Permalink to &quot;认证&quot;">​</a></h2><p><strong>前往 Discord：</strong></p><ol><li>在主界面 - 信息页点击 Discord 按钮</li><li>按指引接受邀请并登陆或注册 Discord</li><li>加入 MissFisher 的服务器</li></ol><p>请注意，在认证后，识别凭证会与你的 Discord 账号绑定。</p><p><strong>在 Discord 认证：</strong></p><ol><li>选择「点这里认证」频道（如果没有在侧栏找到，点击左上角的服务器名，勾选显示所有频道）</li><li>点击聊天输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/verify</code></li><li>回到游戏，在 MissFisher 主界面的信息页中，点击想要认证的任一识别凭证码，点击后应会自动被复制到剪贴板</li><li>回到浏览器，将识别凭证填入下方输入框、命令参数输入框中（cert_id 小框中）</li><li>发送并等待认证机器人完成认证操作</li></ol><h2 id="替换凭证" tabindex="-1">替换凭证 <a class="header-anchor" href="#替换凭证" aria-label="Permalink to &quot;替换凭证&quot;">​</a></h2><p>你可以在 MissFisher 的 Discord 中的「点这里认证」频道中使用 <code>/replace</code> 命令来将旧凭证替换为新凭证：</p><p><strong>获取指引与旧凭证：</strong></p><ol><li>进入 MissFisher 的 Discord 的「点这里认证」频道</li><li>点击输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/replace</code></li><li>回到游戏，在 MissFisher 主界面的信息页中，点击想要认证的任一识别凭证以将其复制到剪贴板</li><li>回到浏览器，将识别凭证粘贴到命令参数输入框中，发送以获取指引</li></ol><p><strong>用新凭证替换旧凭证：</strong></p><ol><li>点击输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/replace</code></li><li>将识别凭证粘贴到命令参数输入框中</li><li>点击补全列表中的 <code>old_cert_id</code></li><li>复制机器人回复的指引中想要替换掉的识别凭证 - 粘贴到第 2 个命令参数输入框中</li><li>发送并等待机器人响应</li></ol><h2 id="临时免验凭证" tabindex="-1">临时免验凭证 <a class="header-anchor" href="#临时免验凭证" aria-label="Permalink to &quot;临时免验凭证&quot;">​</a></h2><p>临时免验凭证是为了应对验证服务器的状态波动而准备的。<br> 在发生验证服务器状态波动而导致服务断连时，作者会在 Discord 发布临时免验凭证（不保证一定发布，也不保证在服务断连后立刻发布）。</p><p>它会发布后数天内过期，且通常只适用于最新版本。</p><p><strong>使用临时免验凭证</strong></p><ol><li>在 Discord 的公告频道复制临时免验凭证</li><li>打开 MissFisher 主界面</li><li>粘贴在临时免验凭证的输入框内，通常会立刻生效</li></ol>',24)])])}const _=l(s,[["render",a]]);export{u as __pageData,_ as default};
